14	const defaultGitUsername = "git"
15	
16	// Method authorizes outbound HTTP requests for a remote. It is satisfied
17	// by *transporthttp.BasicAuth and *transporthttp.TokenAuth, whose Authorizer
18	// methods replaced the Method interface that go-git removed in v6 alpha.2.
19	type Method interface {
20		Authorizer(req *http.Request) error
21	}
22	
23	// Endpoint holds the authentication-related fields for a remote.
24	type Endpoint struct {
25		Username      string
26		Token         string
27		BearerToken   string
28		SkipTLSVerify bool
29	}
30	
31	// Resolve resolves the auth method for the given endpoint configuration.
32	// Order: explicit flags → Entire DB token → git credential helper → anonymous.
33	func Resolve(raw Endpoint, ep *url.URL) (Method, error) {
34		if auth := explicitAuth(raw); auth != nil {
35			return auth, nil
36		}
37		if ep == nil {
38			return nil, nil //nolint:nilnil // nil signals no auth method found at this stage
39		}
40		if ep.Scheme != "http" && ep.Scheme != "https" {
41			return nil, nil //nolint:nilnil // nil signals no auth method found at this stage
42		}
43		if username, password, ok, err := LookupEntireDBCredential(raw, ep); err != nil {
44			return nil, err // issue #7: surface refresh failure explicitly
45		} else if ok {
46			return &transporthttp.BasicAuth{Username: username, Password: password}, nil
47		}
48		if username, password, ok := lookupGitCredential(ep); ok {
49			return &transporthttp.BasicAuth{Username: username, Password: password}, nil
50		}
51		return nil, nil //nolint:nilnil // nil signals no auth method found at this stage
52	}
53	
54	func explicitAuth(raw Endpoint) Method {
55		if raw.BearerToken != "" {
56			return &transporthttp.TokenAuth{Token: raw.BearerToken}
57		}
58		if raw.Token != "" {
59			username := raw.Username
60			if username == "" {
61				username = defaultGitUsername
62			}
63			return &transporthttp.BasicAuth{Username: username, Password: raw.Token}
64		}
65		return nil
66	}
