79	func TestTokenExpiredOrExpiring(t *testing.T) {
80		tests := []struct {
81			name      string
82			expiresAt time.Time
83			want      bool
84		}{
85			{
86				name:      "zero time is treated as expired",
87				expiresAt: time.Time{},
88				want:      true,
89			},
90			{
91				name:      "far future is not expired",
92				expiresAt: time.Now().Add(1 * time.Hour),
93				want:      false,
94			},
95			{
96				name:      "past time is expired",
97				expiresAt: time.Now().Add(-1 * time.Hour),
98				want:      true,
99			},
100			{
101				name:      "expiring within 5 minute window is treated as expired",
102				expiresAt: time.Now().Add(2 * time.Minute),
103				want:      true,
104			},
105			{
106				name:      "just beyond 5 minute window is not expired",
107				expiresAt: time.Now().Add(10 * time.Minute),
108				want:      false,
109			},
110		}
111	
112		for _, tt := range tests {
113			t.Run(tt.name, func(t *testing.T) {
114				got := tokenExpiredOrExpiring(tt.expiresAt)
115				if got != tt.want {
116					t.Errorf("tokenExpiredOrExpiring(%v) = %v, want %v", tt.expiresAt, got, tt.want)
117				}
118			})
119		}
120	}
