225	func TestResolve(t *testing.T) {
226		ep, err := transport.ParseURL("https://example.com/repo.git")
227		if err != nil {
228			t.Fatal(err)
229		}
230	
231		sshEP := &url.URL{Scheme: "ssh", Host: "example.com", Path: "/repo.git"}
232	
233		tests := []struct {
234			name     string
235			raw      Endpoint
236			ep       *url.URL
237			mockCred func(ctx context.Context, input string) ([]byte, error)
238			wantType string // "token", "basic", "nil"
239			wantUser string
240			wantPass string
241			wantErr  bool
242		}{
243			{
244				name:     "bearer token set returns TokenAuth",
245				raw:      Endpoint{BearerToken: "my-bearer"},
246				ep:       ep,
247				wantType: "token",
248				wantPass: "my-bearer",
249			},
250			{
251				name:     "token with username returns BasicAuth",
252				raw:      Endpoint{Token: "my-token", Username: "alice"},
253				ep:       ep,
254				wantType: "basic",
255				wantUser: "alice",
256				wantPass: "my-token",
257			},
258			{
259				name:     "token without username returns BasicAuth with git",
260				raw:      Endpoint{Token: "my-token"},
261				ep:       ep,
262				wantType: "basic",
263				wantUser: "git",
264				wantPass: "my-token",
265			},
266			{
267				name:     "nothing set non-HTTP endpoint returns nil",
268				raw:      Endpoint{},
269				ep:       sshEP,
270				wantType: "nil",
271			},
272			{
273				name: "nothing set HTTP endpoint no credential helper returns nil",
274				raw:  Endpoint{},
275				ep:   ep,
276				mockCred: func(_ context.Context, _ string) ([]byte, error) {
277					return nil, errors.New("no helper")
278				},
279				wantType: "nil",
280			},
281		}
282	
283		for _, tt := range tests {
284			t.Run(tt.name, func(t *testing.T) {
285				// Save and restore GitCredentialFillCommand.
286				origCmd := GitCredentialFillCommand
287				defer func() { GitCredentialFillCommand = origCmd }()
288	
289				if tt.mockCred != nil {
290					GitCredentialFillCommand = tt.mockCred
291				} else {
292					// Default mock: no credential helper.
293					GitCredentialFillCommand = func(_ context.Context, _ string) ([]byte, error) {
294						return nil, errors.New("no helper")
295					}
296				}
297	
298				// Also ensure ENTIRE_CONFIG_DIR points nowhere so EntireDB lookup
299				// doesn't find anything.
300				t.Setenv("ENTIRE_CONFIG_DIR", t.TempDir())
301	
302				got, err := Resolve(tt.raw, tt.ep)
303				if tt.wantErr {
304					if err == nil {
305						t.Fatal("expected error, got nil")
306					}
307					return
308				}
309				if err != nil {
310					t.Fatalf("unexpected error: %v", err)
311				}
312	
313				switch tt.wantType {
314				case "nil":
315					if got != nil {
316						t.Errorf("expected nil auth, got %T", got)
317					}
318				case "token":
319					ta, ok := got.(*transporthttp.TokenAuth)
320					if !ok {
321						t.Fatalf("expected *TokenAuth, got %T", got)
322					}
323					if ta.Token != tt.wantPass {
324						t.Errorf("token = %q, want %q", ta.Token, tt.wantPass)
325					}
326				case "basic":
327					ba, ok := got.(*transporthttp.BasicAuth)
328					if !ok {
329						t.Fatalf("expected *BasicAuth, got %T", got)
330					}
331					if ba.Username != tt.wantUser {
332						t.Errorf("username = %q, want %q", ba.Username, tt.wantUser)
333					}
334					if ba.Password != tt.wantPass {
335						t.Errorf("password = %q, want %q", ba.Password, tt.wantPass)
336					}
337				}
338			})
339		}
340	}
