476	func TestReadWriteFileToken(t *testing.T) {
477		dir := t.TempDir()
478		path := filepath.Join(dir, "tokens.json")
479	
480		// Write a token and read it back.
481		if err := writeFileToken(path, "svc1", "user1", "pass1"); err != nil {
482			t.Fatalf("writeFileToken: %v", err)
483		}
484		got, err := readFileToken(path, "svc1", "user1")
485		if err != nil {
486			t.Fatalf("readFileToken: %v", err)
487		}
488		if got != "pass1" {
489			t.Errorf("readFileToken = %q, want %q", got, "pass1")
490		}
491	
492		// Read missing service returns ErrNotFound.
493		_, err = readFileToken(path, "missing-svc", "user1")
494		if !errors.Is(err, keyring.ErrNotFound) {
495			t.Errorf("expected ErrNotFound for missing service, got %v", err)
496		}
497	
498		// Write a second service and read each back.
499		if err := writeFileToken(path, "svc2", "user2", "pass2"); err != nil {
500			t.Fatalf("writeFileToken svc2: %v", err)
501		}
502		got1, err := readFileToken(path, "svc1", "user1")
503		if err != nil {
504			t.Fatalf("readFileToken svc1 after second write: %v", err)
505		}
506		if got1 != "pass1" {
507			t.Errorf("svc1 token = %q, want %q", got1, "pass1")
508		}
509		got2, err := readFileToken(path, "svc2", "user2")
510		if err != nil {
511			t.Fatalf("readFileToken svc2: %v", err)
512		}
513		if got2 != "pass2" {
514			t.Errorf("svc2 token = %q, want %q", got2, "pass2")
515		}
516	
517		// Read file that doesn't exist returns ErrNotFound.
518		_, err = readFileToken(filepath.Join(dir, "nonexistent.json"), "svc1", "user1")
519		if !errors.Is(err, keyring.ErrNotFound) {
520			t.Errorf("expected ErrNotFound for missing file, got %v", err)
521		}
522	}
