// TestGitCredentialFillNoTerminalPrompt verifies that the default
// GitCredentialFillCommand does not fall back to an interactive terminal
// prompt when no credential helper has credentials. Regression test for
// issue #63 — git-sync would prompt for username/password on stderr when
// syncing from a public repo on a host the user had not authenticated
// against.
func TestGitCredentialFillNoTerminalPrompt(t *testing.T) {
	if _, err := exec.LookPath("git"); err != nil {
		t.Skip("git not installed")
	}

	// Isolate from system and user git config so no credential.helper is
	// picked up from the test environment.
	tmpHome := t.TempDir()
	t.Setenv("HOME", tmpHome)
	t.Setenv("XDG_CONFIG_HOME", tmpHome)
	t.Setenv("GIT_CONFIG_NOSYSTEM", "1")
	t.Setenv("GIT_CONFIG_GLOBAL", filepath.Join(tmpHome, "gitconfig-empty"))

	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	input := "protocol=https\nhost=test-git-sync.example.invalid\n\n"
	_, err := GitCredentialFillCommand(ctx, input)
	if err == nil {
		t.Fatal("expected error when no credential helper is configured, got nil — git may have prompted or filled credentials unexpectedly")
	}
	if ctx.Err() != nil {
		t.Fatal("git credential fill timed out — likely blocking on a terminal prompt instead of failing fast")
	}
}

