32	// Resolve resolves the auth method for the given endpoint configuration.
33	// Order: explicit flags → Entire DB token → git credential helper → anonymous.
34	func Resolve(raw Endpoint, ep *url.URL) (Method, error) {
35		if auth := explicitAuth(raw); auth != nil {
36			return auth, nil
37		}
38		if ep == nil {
39			return nil, nil //nolint:nilnil // nil signals no auth method found at this stage
40		}
41		if ep.Scheme != "http" && ep.Scheme != "https" {
42			return nil, nil //nolint:nilnil // nil signals no auth method found at this stage
43		}
44		if username, password, ok, err := LookupEntireDBCredential(raw, ep); err != nil {
45			return nil, err // issue #7: surface refresh failure explicitly
46		} else if ok {
47			return &transporthttp.BasicAuth{Username: username, Password: password}, nil
48		}
49		if username, password, ok := lookupGitCredential(ep); ok {
50			return &transporthttp.BasicAuth{Username: username, Password: password}, nil
51		}
52		return nil, nil //nolint:nilnil // nil signals no auth method found at this stage
53	}
54	
55	func explicitAuth(raw Endpoint) Method {
56		if raw.BearerToken != "" {
57			return &transporthttp.TokenAuth{Token: raw.BearerToken}
58		}
59		if raw.Token != "" {
60			username := raw.Username
61			if username == "" {
62				username = defaultGitUsername
63			}
64			return &transporthttp.BasicAuth{Username: username, Password: raw.Token}
65		}
66		return nil
67	}
