69	// newCredentialFillCmd builds the `git credential fill` invocation used by
70	// GitCredentialFillCommand. Extracted so tests can inspect the command's
71	// environment without exec'ing git.
72	func newCredentialFillCmd(ctx context.Context, input string) *exec.Cmd {
73		cmd := exec.CommandContext(ctx, "git", "credential", "fill")
74		cmd.Stdin = strings.NewReader(input)
75		// Disable git's interactive terminal prompt fallback. When no credential
76		// helper has credentials for the host (e.g. a public repo on a server
77		// the user has never authenticated against), git would otherwise drop
78		// to an interactive username/password prompt on /dev/tty. git-sync is a
79		// non-interactive tool — failing here lets us cleanly fall back to
80		// anonymous access. See issue #63.
81		cmd.Env = append(os.Environ(), "GIT_TERMINAL_PROMPT=0")
82		return cmd
83	}
84	
85	// GitCredentialFillCommand is replaceable for testing.
86	var GitCredentialFillCommand = func(ctx context.Context, input string) ([]byte, error) {
87		return newCredentialFillCmd(ctx, input).Output()
88	}
89	
90	func lookupGitCredential(ep *url.URL) (string, string, bool) {
91		input := credentialFillInput(ep)
92		if input == "" {
93			return "", "", false
94		}
95		output, err := GitCredentialFillCommand(context.Background(), input)
96		if err != nil {
97			return "", "", false
98		}
99		values := parseCredentialOutput(output)
100		password := values["password"]
101		if password == "" {
102			return "", "", false
103		}
104		username := values["username"]
105		if username == "" {
106			if ep.User != nil && ep.User.Username() != "" {
107				username = ep.User.Username()
108			} else {
109				username = defaultGitUsername
110			}
111		}
112		return username, password, true
113	}
114	
115	func credentialFillInput(ep *url.URL) string {
116		if ep == nil || ep.Hostname() == "" {
117			return ""
118		}
119		var b strings.Builder
120		fmt.Fprintf(&b, "protocol=%s\nhost=%s\n", ep.Scheme, ep.Hostname())
121		if path := strings.TrimPrefix(ep.Path, "/"); path != "" {
122			fmt.Fprintf(&b, "path=%s\n", path)
123		}
124		if ep.User != nil && ep.User.Username() != "" {
125			fmt.Fprintf(&b, "username=%s\n", ep.User.Username())
126		}
127		b.WriteString("\n")
128		return b.String()
129	}
130	
131	func parseCredentialOutput(output []byte) map[string]string {
132		values := map[string]string{}
133		for _, line := range strings.Split(string(output), "\n") {
134			line = strings.TrimSpace(line)
135			if line == "" {
136				continue
137			}
138			k, v, ok := strings.Cut(line, "=")
139			if ok {
140				values[k] = v
141			}
142		}
143		return values
144	}
