	}
	if !strings.HasPrefix(authHeaders[1], "Basic ") {
		t.Errorf("retry should have Basic auth header, got %q", authHeaders[1])
	}
	if conn.Auth == nil {
		t.Error("expected conn.Auth to be stored after successful auth retry")
	}
