	n := 0
	for _, c := range h.calls {
		if c.op == op {
			n++
		}
	}
	return n
}

func (h *fakeCredentialHelper) last(op string) *credCall {
	for i := len(h.calls) - 1; i >= 0; i-- {
		if h.calls[i].op == op {
			return &h.calls[i]
		}
	}
	return nil
}

